// =============================================
// Safe Extraction
// =============================================

// Main data
const inputData = $input.first()?.json || {};
const localResults = inputData.local_results || [];

// Try to safely get user config
let userConfig = {};

try {
  userConfig = $('User Input Configuration')?.item?.json || {};
} catch (error) {
  console.log('User Input Configuration node not found. Using empty config.');
}

// Logging
console.log(`Processing ${localResults.length} search results for: ${userConfig.search_query || 'N/A'}`);

const places = localResults
  .map(place => {

    return {
      place_name: place.title || 'Unknown',
      address: place.address || 'No address',
      type: place.type || 'Unknown',

      rating: place.rating || 'No rating',
      reviews_count: place.reviews || 0,
      reviews_link: place.reviews_link || null,

      data_id: place.data_id || null,
      place_id: place.place_id || null,
      lsig: place.lsig || null,

      phone: place.phone || null,
      website: place.website || null,

      thumbnail: place.thumbnail || null,
      operating_hours: place.operating_hours || null,
      price_level: place.price_level || null,
      plus_code: place.plus_code || null,

      coordinates: {
        lat: place.gps_coordinates?.latitude || null,
        lng: place.gps_coordinates?.longitude || null
      },

      search_context: {
        original_query: userConfig.search_query || null,
        analysis_focus: userConfig.analysis_focus || null,
        city: userConfig.city_name || null,
        search_timestamp: new Date().toISOString()
      }
    };
  })

  .filter(place =>
    place.reviews_link ||
    (place.rating && place.rating !== 'No rating') ||
    place.reviews_count > 0
  );

console.log(`Filtered to ${places.length} places`);

return places.map(place => ({ json: place }));

// Safe data access with fallback protection

let currentItem = {};
let userConfig = {};
let reviewsResponse = {};

try {
    currentItem = $('Loop Over Items')?.item?.json || {};
} catch (error) {
    console.log('Loop Over Items node not found');
}

try {
    userConfig = $('User Input Configuration')?.item?.json || {};
} catch (error) {
    console.log('User Input Configuration node not found');
}

try {
    reviewsResponse = $input.first()?.json || {};
} catch (error) {
    console.log('No reviews input found');
}


// Function to calculate completeness score
function calculateCompletenessScore(placeData = {}) {
    const fields = [
        'place_name',
        'address',
        'rating',
        'phone',
        'website',
        'operating_hours'
    ];

    const filledFields = fields.filter(field =>
        placeData?.[field] &&
        placeData[field] !== 'Unknown' &&
        placeData[field] !== 'No address'
    );

    return fields.length
        ? Math.round((filledFields.length / fields.length) * 100)
        : 0;
}


// Build combined data safely
const combinedData = {

    place_name: currentItem.place_name || null,
    address: currentItem.address || null,
    rating: currentItem.rating || null,
    reviews_count: currentItem.reviews_count || 0,
    data_id: currentItem.data_id || null,
    type: currentItem.type || null,
    phone: currentItem.phone || null,
    website: currentItem.website || null,
    coordinates: currentItem.coordinates || null,
    operating_hours: currentItem.operating_hours || null,
    price_level: currentItem.price_level || null,

    reviews_content: Object.keys(reviewsResponse).length
        ? reviewsResponse
        : { error: 'No reviews data available' },

    analysis_metadata: {
        search_query: userConfig.search_query || null,
        analysis_focus: userConfig.analysis_focus || null,
        target_city: userConfig.city_name || null,
        data_collection_time: new Date().toISOString(),
        has_reviews: !!reviewsResponse?.reviews,
        review_source: currentItem.reviews_link || 'No review link',
        place_completeness_score: calculateCompletenessScore(currentItem)
    }
};


// Debug logs
console.log(
    `Processing ${combinedData.analysis_metadata.analysis_focus || 'Unknown'}: ${combinedData.place_name || 'Unnamed Place'}`
);

console.log(
    `Data completeness: ${combinedData.analysis_metadata.place_completeness_score}%`
);


// Final return
return {
    json: combinedData
};

// 1. DYNAMIC DATA DISCOVERY
const allPlaces = $input.all();

let userConfig = {};

try {
    // We attempt to find the node that started the workflow
    // If your form node has a different name, change "On form submission" below
    userConfig = $('On form submission').first().json;
} catch (e) {
    try {
        // Fallback: Try the "Edit Fields" node if that's where you defined the focus
        userConfig = $('Edit Fields').first().json;
    } catch (e2) {
        // Last Resort: Use a placeholder so the code doesn't error out
        userConfig = {
            analysis_focus: "Market Research",
            city_name: "Local Area",
            search_query: "General Search"
        };
        console.log("Using default config because trigger nodes weren't found.");
    }
}

// 2. INITIALIZE PROMPT
let analysisPrompt = `MARKET RESEARCH DATA ANALYSIS\n`;
analysisPrompt += `Research Focus: ${userConfig.analysis_focus || 'N/A'}\n`;
analysisPrompt += `Location: ${userConfig.city_name || 'N/A'}\n`;
analysisPrompt += `Search Query: "${userConfig.search_query || 'N/A'}"\n`;
analysisPrompt += `Total Locations Found: ${allPlaces.length}\n`;
analysisPrompt += `Analysis Date: ${new Date().toLocaleDateString('vi-VN')}\n\n`;

analysisPrompt += `=== DATASET OVERVIEW ===\n`;

// 3. STATS TRACKING
let totalReviews = 0;
let totalRatingSum = 0;
let ratedCount = 0;
let completenessScores = [];

// 4. PROCESS EACH PLACE (Like "EDTECH EDU LLC")
allPlaces.forEach((place, index) => {
    const data = place.json;

    // Statistics Calculation
    if (data.reviews_count) totalReviews += parseInt(data.reviews_count) || 0;
    if (data.rating && data.rating !== 'No rating') {
        totalRatingSum += parseFloat(data.rating);
        ratedCount++;
    }

    // Safety check for metadata
    const compScore = data.analysis_metadata?.place_completeness_score;
    if (compScore) completenessScores.push(compScore);

    // Build Entry String
    analysisPrompt += `\n${index + 1}. ${data.place_name || 'Unknown'}\n`;
    analysisPrompt += `   Address: ${data.address || 'N/A'}\n`;
    analysisPrompt += `   Rating: ${data.rating || 'N/A'}/5 (${data.reviews_count || 0} reviews)\n`;

    if (data.phone) analysisPrompt += `   Phone: ${data.phone}\n`;
    if (data.website) analysisPrompt += `   Website: ${data.website}\n`;

    // Add Hours (Formatted)
    if (data.operating_hours) {
        analysisPrompt += `   Hours: ${data.operating_hours.monday || 'Closed'} - ${data.operating_hours.friday || 'Closed'}\n`;
    }

    analysisPrompt += `   Data Completeness: ${compScore ?? 'N/A'}%\n`;
    analysisPrompt += `\n${'-'.repeat(40)}\n`;
});

// 5. CALCULATE AVERAGES
const avgRating = ratedCount > 0 ? (totalRatingSum / ratedCount).toFixed(2) : 0;
const avgComp = completenessScores.length > 0 ? 
    (completenessScores.reduce((a, b) => a + b, 0) / completenessScores.length).toFixed(1) : 'N/A';

analysisPrompt += `\n=== SUMMARY STATISTICS ===\n`;
analysisPrompt += `Average Rating: ${avgRating}/5\n`;
analysisPrompt += `Average Completeness: ${avgComp}%\n`;

// 6. FINAL OUTPUT
return {
    analysis_prompt: analysisPrompt,
    summary_stats: {
        total_places: allPlaces.length,
        average_rating: avgRating,
        average_completeness: avgComp
    },
    raw_data: allPlaces.map(p => p.json)
};

